UPDATE public.document_templates
SET conteudo = '<p style="text-align: justify;">Declaramos, para os devidos fins, que a paciente <strong>{{nome_paciente}}</strong>, CPF nº <strong>{{cpf}}</strong>, inscrita no CNS sob o nº <strong>{{cns}}</strong>, data de nascimento <strong>{{data_nascimento}}</strong>, encontra-se em acompanhamento nesta Unidade de Saúde, sendo atendida pelo Centro de Especialidades em Reabilitação — CER II, localizado no município de Oriximiná, Estado do Pará.</p><p style="text-align: justify;">A referida paciente compareceu a esta unidade na data de <strong>{{data_atendimento}}</strong>, no período das <strong>{{horario_entrada}}</strong> às <strong>{{horario_saida}}</strong>, sob responsabilidade do profissional <strong>{{profissional}}</strong>.</p><p style="text-align: justify;">O comparecimento deu-se para fins de: <strong>{{finalidade}}</strong>, impossibilitando seu comparecimento a outras atividades neste período. Expedimos a presente declaração para fins de justificativa junto às instituições que se fizerem necessárias.</p>',
    updated_at = now()
WHERE id = '973ebe42-1910-46e4-a71b-4dbbe64b17ae';